/** Returns a resolved { uri, type } or null if the word has no local asset. */
export const resolveSignAsset = (
  word: string,
): { uri: string; type: LocalSignEntry["type"] } | null => {
  const key = word.toLowerCase().trim();
  const entry = RAW_MAP[key];
  if (!entry) return null;
  try {
    const resolved = Image.resolveAssetSource(entry.source);
    if (!resolved?.uri) return null;
    return { uri: resolved.uri, type: entry.type };
  } catch {
    return null;
  }
};

